def calculate_total(items):
    total = 0.0
    for item in items:
        if 'price' in item:
            total += item['price']
    return total

def process_order(order_id, items):
    total = calculate_total(items)
    return {
        'order_id': order_id,
        'total': total,
        'status': 'processed'
    }

if __name__ == '__main__':
    valid_items = [
        {'name': 'Item 1', 'price': 10.0},
        {'name': 'Item 2', 'price': 20.0}
    ]
    result = process_order('ORD-001', valid_items)
    print(f"Order result: {result}")

    invalid_items = [
        {'name': 'Item 3', 'price': 15.0},
        {'name': 'Item 4'}
    ]
    result = process_order('ORD-002', invalid_items)
    print(f"Order result: {result}")

